import sys, json, base64
sys.path.insert(0, ".")
calendar = json.loads(base64.b64decode("").decode())
from db.connection import get_conn
with get_conn() as conn:
    with conn.cursor() as cur:
        cur.execute(
            "INSERT INTO decisions (decided_by, decision_type, input_context, reasoning, output) VALUES (%s, %s, %s::jsonb, %s, %s::jsonb)",
            ("claude_direct", "calendar_plan",
             json.dumps({"source": "manual_complete", "month": "2026-05"}),
             "Complete calendar May 14-31. Includes: Hive Mind every 3 days (prospects), sleep audio every 3 days (customers split seal/non-seal), pre-paid/membership offers, Memorial Day, weekends, revenue projections vs $150K goal.",
             json.dumps(calendar)))
    conn.commit()
    print("Calendar inserted — " + str(len(calendar["slots"])) + " slots")
try:
    from pacing.calendar import _generate_html_report, _publish_calendar_page
    from datetime import date
    html = _generate_html_report(date(2026, 5, 1), calendar)
    url = _publish_calendar_page(date(2026, 5, 1), html)
    print("Published:", url)
except Exception as e:
    print("Publish error:", e)
